@Service
class SamlService {
    private final SamlProperties props = new SamlProperties();
    private final Credential signingCredential;

    public SamlService() throws Exception {
        this.signingCredential = generateCredential();
    }

    public String createAuthnRequest() throws Exception {
        AuthnRequest request = (AuthnRequest) XMLObjectSupport.buildXMLObject(AuthnRequest.DEFAULT_ELEMENT_NAME);
        request.setID("_" + UUID.randomUUID());
        request.setVersion(SAMLVersion.VERSION_20);
        request.setIssueInstant(Instant.now());
        request.setDestination(props.getSsoUrl());
        request.setAssertionConsumerServiceURL(props.getAcsUrl());

        Issuer issuer = (Issuer) XMLObjectSupport.buildXMLObject(Issuer.DEFAULT_ELEMENT_NAME);
        issuer.setValue(props.getEntityId());
        request.setIssuer(issuer);

        NameIDPolicy nameIDPolicy = (NameIDPolicy) XMLObjectSupport.buildXMLObject(NameIDPolicy.DEFAULT_ELEMENT_NAME);
        nameIDPolicy.setFormat(NameIDType.PERSISTENT);
        nameIDPolicy.setAllowCreate(true);
        request.setNameIDPolicy(nameIDPolicy);

        RequestedAuthnContext rac = (RequestedAuthnContext) XMLObjectSupport.buildXMLObject(RequestedAuthnContext.DEFAULT_ELEMENT_NAME);
        rac.setComparison(AuthnContextComparisonType.EXACT);
        AuthnContextClassRef classRef = (AuthnContextClassRef) XMLObjectSupport.buildXMLObject(AuthnContextClassRef.DEFAULT_ELEMENT_NAME);
        classRef.setURI(AuthnContext.PASSWORD_AUTHN_CTX);
        rac.getAuthnContextClassRefs().add(classRef);
        request.setRequestedAuthnContext(rac);

        sign(request);
        return encode(deflateAndBase64(serialize(request)));
    }

    public Assertion validateAndExtractAssertion(String samlResponseBase64) throws Exception {
        String xml = inflateBase64(samlResponseBase64);
        XMLObject xmlObject = XMLObjectSupport.unmarshallFromInputStream(XMLObjectProviderRegistrySupport.getParserPool(), new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
        if (!(xmlObject instanceof Response)) {
            throw new IllegalArgumentException("Invalid SAML Response");
        }
        Response response = (Response) xmlObject;
        if (response.getAssertions().isEmpty()) {
            throw new IllegalArgumentException("No assertions found");
        }
        Assertion assertion = response.getAssertions().get(0);
        if (assertion.getSignature() != null) {
            SignatureValidator.validate(assertion.getSignature(), (Credential) signingCredential);
        }
        return assertion;
    }

    public Metadata getMetadata() {
        EntityDescriptor entityDescriptor = (EntityDescriptor) XMLObjectSupport.buildXMLObject(EntityDescriptor.DEFAULT_ELEMENT_NAME);
        entityDescriptor.setEntityID(props.getEntityId());

        SPSSODescriptor spSsoDescriptor = (SPSSODescriptor) XMLObjectSupport.buildXMLObject(SPSSODescriptor.DEFAULT_ELEMENT_NAME);
        spSsoDescriptor.addSupportedProtocol(SAMLVersion.VERSION_20.getVersionString());

        AssertionConsumerService acs = (AssertionConsumerService) XMLObjectSupport.buildXMLObject(AssertionConsumerService.DEFAULT_ELEMENT_NAME);
        acs.setBinding(ACSBinding.POST);
        acs.setLocation(props.getAcsUrl());
        acs.setIndex(0);
        acs.setIsDefault(true);
        spSsoDescriptor.getAssertionConsumerServices().add(acs);

        entityDescriptor.getRoleDescriptors().add(spSsoDescriptor);
        return entityDescriptor;
    }

    private void sign(XMLObject xmlObject) throws Exception {
        Signature signature = (Signature) XMLObjectSupport.buildXMLObject(Signature.DEFAULT_ELEMENT_NAME);
        signature.setSigningCredential(signingCredential);
        signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);
        xmlObject.setSignature(signature);
        XMLObjectSupport.marshall(xmlObject);
        Signer.signObject(signature);
    }

    private Credential generateCredential() throws Exception {
        KeyPairGenerator kpg = KeyPairGenerator.getInstance("RSA");
        kpg.initialize(2048, new SecureRandom());
        KeyPair kp = kpg.generateKeyPair();
        return new BasicCredential(kp.getPublic(), kp.getPrivate());
    }

    private String serialize(XMLObject xmlObject) throws MarshallingException {
        org.w3c.dom.Element element = XMLObjectSupport.marshall(xmlObject);
        return XMLObjectSupport.prettyPrintXML(element);
    }

    private String deflateAndBase64(String xml) {
        return Base64.getEncoder().encodeToString(xml.getBytes(StandardCharsets.UTF_8));
    }

    private String encode(String value) {
        return value;
    }

    private String inflateBase64(String base64) {
        return new String(Base64.getDecoder().decode(base64), StandardCharsets.UTF_8);
    }
}

@RestController
@RequestMapping("/saml")
class SamlController {
    private final SamlService samlService;

    public SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public String metadata() throws Exception {
        return XMLObjectSupport.prettyPrintXML(XMLObjectSupport.marshall(samlService.getMetadata()));
    }

    @GetMapping(value = "/login", produces = MediaType.TEXT_HTML_VALUE)
    public String login() throws Exception {
        String samlRequest = samlService.createAuthnRequest();
        return "<html><body onload=\"document.forms[0].submit()\">" +
                "<form method='post' action='" + "https://idp.example.com/sso" + "'>" +
                "<input type='hidden' name='SAMLRequest' value='" + samlRequest + "'/>" +
                "</form></body></html>";
    }

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE, produces = MediaType.TEXT_HTML_VALUE)
    public String acs(@RequestParam("SAMLResponse") String samlResponse, HttpServletRequest request, HttpServletResponse response) throws Exception {
        Assertion assertion = samlService.validateAndExtractAssertion(samlResponse);
        String nameId = assertion.getSubject() != null && assertion.getSubject().getNameID() != null ? assertion.getSubject().getNameID().getValue() : "unknown";
        return "<html><body>SSO success for " + nameId + "</body></html>";
    }
}